import sys

def load_dictionary(file_path):
    dictionary = {}
    with open(file_path, 'r') as file:
        for line in file:
            if ':' in line:
                word, definition = line.split(':', 1)
                dictionary[word.strip()] = definition.strip()
    return dictionary

def lookup_word(dictionary, word):
    return dictionary.get(word, "Word not found in dictionary.")

def main():
    if len(sys.argv) != 3:
        print("Usage: python script.py dictionary_file.txt word_to_lookup")
        sys.exit(1)

    dictionary_file = sys.argv[1]
    word_to_lookup = sys.argv[2]

    dictionary = load_dictionary(dictionary_file)
    definition = lookup_word(dictionary, word_to_lookup)
    print(f"{word_to_lookup}: {definition}")

if __name__ == "__main__":
    main()

